+        let (passed, message, max_diff, tolerance_used) =
+            compare_array_api_case_differential(case, &observed);
+        per_case_results.push(DifferentialCaseResult {
+            case_id: case.case_id().to_owned(),
+            passed,
+            message,
+            max_diff,
+            tolerance_used,
+            oracle_status: oracle_status.clone(),
+        });
+    }
+
